# Anti-pattern: one key for every message serializes the whole topic
for order in orders:
    publisher.publish(topic_path, order.to_bytes(), ordering_key="orders")

# Fix: key on the actual ordering boundary
for order in orders:
    publisher.publish(topic_path, order.to_bytes(), ordering_key=order.customer_id)

